function validateProduct(product: Product | null): void {
  if (!product) throw new Error('null');
  if (!product.name) throw new Error('name required');
}

function create(product: Product | null): void {
  validateProduct(product);
  repo.add(product!);
}

function update(product: Product | null): void {
  validateProduct(product);
  repo.update(product!);
}

function mapToDto(user: User): UserDto {
  return { id: user.id, name: user.name, email: user.email };
}

const mapUser = mapToDto;
const mapAdmin = mapToDto;
